#include <stdio.h>
#include <stdint.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long N; scanf("%lld", &N);
        if (N == 1) {
            printf("1 1\n");
            continue;
        }
        long long d = N - 1;
        long long sum_first = (N - 1) * N / 2; // sum 1..N-1
        long long pow2 = 1LL << N; // 2^N, N<=60 fits in 64‑bit
        long long S = pow2 - d - sum_first;
        // output 1..N-2, then d twice, then S
        for (long long i = 1; i <= N - 2; ++i) {
            printf("%lld ", i);
        }
        printf("%lld %lld %lld\n", d, d, S);
    }
    return 0;
}

