const fs = require('fs');
const input = fs.readFileSync(0, 'utf8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let out = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  if (N === 1) {
    out.push('1 1');
    continue;
  }
  const d = N - 1;
  const sumFirst = BigInt(N - 1) * BigInt(N) / 2n; // 1..N-1
  const pow2 = 1n << BigInt(N); // 2^N as BigInt
  const S = pow2 - BigInt(d) - sumFirst;
  // build sequence using normal numbers for the small part and BigInt for S
  let parts = [];
  for (let i = 1; i <= N - 2; ++i) parts.push(i.toString());
  parts.push(d.toString(), d.toString(), S.toString());
  out.push(parts.join(' '));
}
